// Get the raw LLM response text from previous node
// e.g. previous node output: { "response": "Here are your 5 CFO-grade charts:\n\n```json\n{ ... }```" }
const raw = $input.first().json.content[0].text;

// Helper: extract JSON block inside ```json ... ```
function extractJsonBlock(text) {
  // Try to find fenced ```json code block first
  const fenceStart = text.indexOf('```json');
  if (fenceStart !== -1) {
    const afterFence = text.slice(fenceStart + '```json'.length);
    const fenceEnd = afterFence.indexOf('```');
    const jsonSnippet = fenceEnd !== -1 ? afterFence.slice(0, fenceEnd) : afterFence;
    return jsonSnippet.trim();
  }

  // Fallback: grab from first "{" to last "}"
  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    return text.slice(firstBrace, lastBrace + 1).trim();
  }

  throw new Error('No JSON block found in text.');
}

let parsed;
try {
  const jsonString = extractJsonBlock(raw);
  parsed = JSON.parse(jsonString);
} catch (error) {
  throw new Error('Failed to parse JSON from response: ' + error.message);
}

// Ensure we have chart_list
if (!parsed.chart_list || !Array.isArray(parsed.chart_list)) {
  throw new Error('Parsed JSON does not contain a valid "chart_list" array.');
}

// Create one n8n item per chart
const outputItems = parsed.chart_list.map(chart => {
  return {
    json: {
      chart_name: chart.chart_name,
      chart_brief_with_numbers: chart.chart_brief_with_numbers,
      chart_type: chart.chart_type,
    },
  };
});

return outputItems;

