return $input.all().map(item => {

  // Get the raw JSON string inside the text field
  let raw = item.json.content[0].text;

  // Remove ```json and ``` if present
  raw = raw.replace(/^```json\s*/, '').replace(/```$/, '');

  // Parse it
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    item.json.error = "Invalid JSON in content[0].text";
    item.json.errorMessage = e.message;
    return item;
  }

  // Attach extracted values
  item.json.pitch_deck = parsed.pitch_deck;
  item.json.no_of_deck = parsed.no_of_deck;

  // Optionally remove original content
  delete item.json.content;

  return item;
});

